import React, { useState } from 'react';
import API from '../api/axios';
import { useNavigate } from 'react-router-dom';

const Login = () => {
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [loading, setLoading] = useState(false);
    const [errorMessage, setErrorMessage] = useState('');
    const [rememberMe, setRememberMe] = useState(false);
    const navigate = useNavigate();

    const handleLogin = async (e) => {
        e.preventDefault();
        setLoading(true);
        setErrorMessage('');
        try {
            const { data } = await API.post('/auth/login', { email, password });

            localStorage.setItem('token', data.token);
            localStorage.setItem('role', data.role);
            localStorage.setItem('userName', data.userName || data.email || 'User');
            localStorage.setItem('userId', data.userId);
            setErrorMessage('');
            navigate('/dashboard');
        } catch (err) {
            const message = err.response?.data?.message || "Invalid email or password";
            setErrorMessage(message);
            console.error('Login error:', message);
        } finally {
            setLoading(false);
        }
    };

    return (
        <div style={styles.loginPage}>
            <style>{`
                @import url('https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700&display=swap');

                * {
                    margin: 0;
                    padding: 0;
                    box-sizing: border-box;
                    font-family: 'Inter', -apple-system, BlinkMacSystemFont, sans-serif;
                }

                .login-container {
                    width: 100%;
                    max-width: 380px;
                    padding: 40px 32px;
                    background: white;
                    border-radius: 12px;
                    box-shadow: 0 4px 20px rgba(0, 0, 0, 0.08);
                }

                .login-header {
                    text-align: center;
                    margin-bottom: 32px;
                }

                .welcome-title {
                    font-size: 28px;
                    font-weight: 700;
                    color: #1a1a1a;
                    margin-bottom: 8px;
                }

                .welcome-subtitle {
                    font-size: 14px;
                    color: #666;
                    font-weight: 400;
                }

                .form-group {
                    margin-bottom: 20px;
                }

                .form-label {
                    display: block;
                    font-size: 14px;
                    font-weight: 500;
                    color: #333;
                    margin-bottom: 8px;
                }

                .form-input {
                    width: 100%;
                    padding: 12px 16px;
                    font-size: 14px;
                    border: 1px solid #ddd;
                    border-radius: 8px;
                    background: #f9f9f9;
                    transition: all 0.2s ease;
                }

                .form-input:focus {
                    outline: none;
                    border-color: #0066ff;
                    background: white;
                    box-shadow: 0 0 0 2px rgba(0, 102, 255, 0.1);
                }

                .form-input::placeholder {
                    color: #999;
                }

                .options-row {
                    display: flex;
                    justify-content: space-between;
                    align-items: center;
                    margin: 24px 0;
                    font-size: 14px;
                }

                .remember-me {
                    display: flex;
                    align-items: center;
                    gap: 8px;
                    color: #333;
                }

                .remember-checkbox {
                    width: 16px;
                    height: 16px;
                    border: 2px solid #ddd;
                    border-radius: 4px;
                    cursor: pointer;
                    background: white;
                }

                .forgot-password {
                    color: #0066ff;
                    text-decoration: none;
                    font-weight: 500;
                    cursor: pointer;
                }

                .forgot-password:hover {
                    text-decoration: underline;
                }

                .login-button {
                    width: 100%;
                    padding: 14px;
                    background: #0066ff;
                    color: white;
                    border: none;
                    border-radius: 8px;
                    font-size: 14px;
                    font-weight: 600;
                    cursor: pointer;
                    transition: background 0.2s ease;
                    margin-bottom: 24px;
                }

                .login-button:hover {
                    background: #0052d4;
                }

                .login-button:disabled {
                    background: #ccc;
                    cursor: not-allowed;
                }

                .divider {
                    text-align: center;
                    position: relative;
                    margin: 24px 0;
                    color: #999;
                    font-size: 14px;
                }

                .divider::before {
                    content: '';
                    position: absolute;
                    left: 0;
                    top: 50%;
                    width: 45%;
                    height: 1px;
                    background: #eee;
                }

                .divider::after {
                    content: '';
                    position: absolute;
                    right: 0;
                    top: 50%;
                    width: 45%;
                    height: 1px;
                    background: #eee;
                }

                .google-button {
                    width: 100%;
                    padding: 14px;
                    background: white;
                    color: #333;
                    border: 1px solid #ddd;
                    border-radius: 8px;
                    font-size: 14px;
                    font-weight: 500;
                    cursor: pointer;
                    transition: all 0.2s ease;
                    display: flex;
                    align-items: center;
                    justify-content: center;
                    gap: 8px;
                    margin-bottom: 24px;
                }

                .google-button:hover {
                    background: #f9f9f9;
                    border-color: #ccc;
                }

                .signup-link {
                    text-align: center;
                    font-size: 14px;
                    color: #666;
                }

                .signup-link a {
                    color: #0066ff;
                    text-decoration: none;
                    font-weight: 500;
                }

                .signup-link a:hover {
                    text-decoration: underline;
                }

                .error-message {
                    background: #ffebee;
                    color: #d32f2f;
                    padding: 12px 16px;
                    border-radius: 8px;
                    font-size: 14px;
                    margin-bottom: 20px;
                    border: 1px solid #ffcdd2;
                }

                @media (max-width: 480px) {
                    .login-container {
                        padding: 32px 24px;
                        margin: 0 16px;
                    }
                }
            `}</style>

            <div className="login-container">
                <div className="login-header">
                    <h1 className="welcome-title">WELCOME BACK</h1>
                    <p className="welcome-subtitle">Welcome back! Please enter your details.</p>
                </div>

                {errorMessage && (
                    <div className="error-message">
                        {errorMessage}
                    </div>
                )}

                <form onSubmit={handleLogin}>
                    <div className="form-group">
                        <label className="form-label">Email</label>
                        <input
                            type="email"
                            className="form-input"
                            placeholder="Enter your email"
                            value={email}
                            onChange={e => setEmail(e.target.value)}
                            required
                        />
                    </div>

                    <div className="form-group">
                        <label className="form-label">Password</label>
                        <input
                            type="password"
                            className="form-input"
                            placeholder="Enter your password"
                            value={password}
                            onChange={e => setPassword(e.target.value)}
                            required
                        />
                    </div>

                    <div className="options-row">
                        <div className="remember-me">
                            <div 
                                className="remember-checkbox"
                                onClick={() => setRememberMe(!rememberMe)}
                                style={{
                                    backgroundColor: rememberMe ? '#0066ff' : 'white',
                                    borderColor: rememberMe ? '#0066ff' : '#ddd',
                                    display: 'flex',
                                    alignItems: 'center',
                                    justifyContent: 'center'
                                }}
                            >
                                {rememberMe && (
                                    <span style={{color: 'white', fontSize: '12px'}}>✓</span>
                                )}
                            </div>
                            <span>Remember me</span>
                        </div>
                        <div className="forgot-password">
                            Forgot password
                        </div>
                    </div>

                    <button 
                        type="submit" 
                        className="login-button"
                        disabled={loading}
                    >
                        {loading ? 'Signing in...' : 'Sign in'}
                    </button>

                    <div className="divider">
                        or
                    </div>

                    <button type="button" className="google-button">
                        <svg width="18" height="18" viewBox="0 0 24 24">
                            <path fill="#4285F4" d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z"/>
                            <path fill="#34A853" d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z"/>
                            <path fill="#FBBC05" d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z"/>
                            <path fill="#EA4335" d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z"/>
                        </svg>
                        Sign in with Google
                    </button>

                    <div className="signup-link">
                        Don't have an account? <a href="#">Sign up for free!</a>
                    </div>
                </form>
            </div>
        </div>
    );
};

